import React, { useEffect, useMemo, useState } from 'react';
import { Expand, Minimize2 } from 'lucide-react';
import { toAbsoluteImageUrl } from '../../utils/imageUrl';

const formatCurrency = (value) =>
  new Intl.NumberFormat('en-US', { style: 'currency', currency: 'USD' }).format(Number(value || 0));

const CUSTOMER_DISPLAY_STATE_KEY = 'khmart_customer_display_state';
const CUSTOMER_QR_IMAGE_PATH = '/images/aba-qr.jpg';
const CUSTOMER_DISPLAY_QR_SPOTLIGHT_KEY = 'khmart_customer_qr_spotlight';
const STAFF_POS_FULLSCREEN_REQUEST_KEY = 'khmart_staff_pos_request';

const getInitialDisplayState = () => ({
  cart: [],
  paymentMethod: 'Cash',
  subtotal: 0,
  discountAmount: 0,
  total: 0,
  amountTendered: 0,
  changeAmount: 0,
  updatedAt: null,
});

const readDisplayState = () => {
  try {
    const raw = localStorage.getItem(CUSTOMER_DISPLAY_STATE_KEY);
    if (!raw) {
      return getInitialDisplayState();
    }

    const parsed = JSON.parse(raw);
    return {
      ...getInitialDisplayState(),
      ...parsed,
      cart: Array.isArray(parsed?.cart) ? parsed.cart : [],
    };
  } catch {
    return getInitialDisplayState();
  }
};

const CustomerDisplay = () => {
  const [displayState, setDisplayState] = useState(() => readDisplayState());
  const [now, setNow] = useState(new Date());
  const [isFullscreen, setIsFullscreen] = useState(Boolean(document.fullscreenElement));
  const [qrSpotlight, setQrSpotlight] = useState(null);
  const [qrSpotlightTick, setQrSpotlightTick] = useState(0);

  const syncFromStorage = () => {
    setDisplayState(readDisplayState());
  };

  useEffect(() => {
    const clockId = setInterval(() => setNow(new Date()), 1000);
    const fallbackSyncId = setInterval(() => syncFromStorage(), 800);

    const onStorage = (event) => {
      if (event.key === CUSTOMER_DISPLAY_STATE_KEY) {
        syncFromStorage();
      }
    };

    const onCustomUpdate = () => syncFromStorage();
    const onFullscreenChange = () => setIsFullscreen(Boolean(document.fullscreenElement));

    const triggerQrSpotlight = (payload) => {
      if (!payload || payload.action !== 'spotlight-qr') {
        return;
      }

      const age = Date.now() - Number(payload.requestedAt || 0);
      if (!Number.isFinite(age) || age > 15000) {
        return;
      }

      setQrSpotlight({
        paymentMethod: payload.paymentMethod || 'ABA',
        subtotal: Number(payload.subtotal || 0),
        discountAmount: Number(payload.discountAmount || 0),
        total: Number(payload.total || 0),
      });
      setQrSpotlightTick((current) => current + 1);
    };

    const onSpotlightStorage = (event) => {
      if (event.key !== CUSTOMER_DISPLAY_QR_SPOTLIGHT_KEY || !event.newValue) {
        return;
      }

      try {
        triggerQrSpotlight(JSON.parse(event.newValue));
      } catch {
        // Ignore malformed cross-tab spotlight payload.
      }
    };

    try {
      const existing = localStorage.getItem(CUSTOMER_DISPLAY_QR_SPOTLIGHT_KEY);
      if (existing) {
        triggerQrSpotlight(JSON.parse(existing));
      }
    } catch {
      // Ignore malformed stored spotlight payload.
    }

    window.addEventListener('storage', onStorage);
    window.addEventListener('khmart-customer-display-updated', onCustomUpdate);
    document.addEventListener('fullscreenchange', onFullscreenChange);
    window.addEventListener('storage', onSpotlightStorage);

    return () => {
      clearInterval(clockId);
      clearInterval(fallbackSyncId);
      window.removeEventListener('storage', onStorage);
      window.removeEventListener('khmart-customer-display-updated', onCustomUpdate);
      document.removeEventListener('fullscreenchange', onFullscreenChange);
      window.removeEventListener('storage', onSpotlightStorage);
    };
  }, []);

  useEffect(() => {
    if (!qrSpotlight) {
      return undefined;
    }

    const timer = window.setTimeout(() => {
      setQrSpotlight(null);
    }, 4300);

    return () => window.clearTimeout(timer);
  }, [qrSpotlightTick, qrSpotlight]);

  const toggleFullscreen = async () => {
    try {
      if (!document.fullscreenElement) {
        await document.documentElement.requestFullscreen();
      } else {
        await document.exitFullscreen();
      }
    } catch {
      // Ignore fullscreen errors on unsupported browsers.
    }
  };

  const goBackToStaff = () => {
    const request = JSON.stringify({
      action: 'open-pos-fullscreen',
      path: '/staff/pos',
      requestedAt: Date.now(),
    });
    localStorage.setItem(STAFF_POS_FULLSCREEN_REQUEST_KEY, request);

    if (window.opener && !window.opener.closed) {
      try {
        window.opener.location.href = '/staff/pos';
        window.opener.focus();
        return;
      } catch {
        // Fallback to same-tab navigation when opener access is restricted.
      }
    }

    window.location.href = '/staff/pos';
  };

  const cart = useMemo(() => (Array.isArray(displayState.cart) ? displayState.cart : []), [displayState.cart]);
  const itemCount = useMemo(() => cart.reduce((sum, item) => sum + (Number(item.qty) || 0), 0), [cart]);
  const subtotal = Number(displayState.subtotal || 0);
  const discountAmount = Number(displayState.discountAmount || 0);
  const total = Number(displayState.total || 0);
  const amountTendered = Number(displayState.amountTendered || 0);
  const changeAmount = Number(displayState.changeAmount || 0);
  const paymentMethod = String(displayState.paymentMethod || 'Cash');

  return (
    <div className="relative h-screen overflow-hidden text-white bg-[radial-gradient(circle_at_8%_8%,rgba(59,130,246,0.24),transparent_36%),radial-gradient(circle_at_95%_0%,rgba(16,185,129,0.24),transparent_30%),linear-gradient(130deg,#0f172a_0%,#111827_50%,#052e2b_100%)]">
      <style>{`
        @keyframes qrSpotlightBackdrop {
          0% { opacity: 0; }
          18% { opacity: 1; }
          82% { opacity: 1; }
          100% { opacity: 0; }
        }
        @keyframes qrSpotlightCard {
          0% { opacity: 0; transform: translate(-50%, -50%) scale(0.28); filter: blur(8px); }
          22% { opacity: 1; transform: translate(-50%, -50%) scale(1.06); filter: blur(0); }
          42% { transform: translate(-50%, -50%) scale(1); }
          86% { opacity: 1; transform: translate(-50%, -50%) scale(1); }
          100% { opacity: 0; transform: translate(-50%, -50%) scale(0.96); }
        }
      `}</style>

      {qrSpotlight && (
        <div
          key={qrSpotlightTick}
          className="pointer-events-none absolute inset-0 z-[120]"
          style={{ animation: 'qrSpotlightBackdrop 4.3s ease both' }}
        >
          <div className="absolute inset-0 bg-slate-950/78 backdrop-blur-[2px]" />
          <div
            className="absolute left-1/2 top-1/2 w-[min(92vw,560px)] rounded-3xl border border-white/20 bg-gradient-to-br from-sky-900/95 via-blue-900/95 to-indigo-900/95 px-5 py-5 shadow-[0_28px_90px_rgba(15,23,42,0.55)]"
            style={{ animation: 'qrSpotlightCard 4.3s cubic-bezier(0.22,0.8,0.22,1) both' }}
          >
            <p className="text-center text-xs font-bold uppercase tracking-[0.2em] text-sky-100/85">Scan To Pay</p>
            <p className="mt-1 text-center text-2xl font-black text-white">{qrSpotlight.paymentMethod} KHQR</p>
            <div className="mx-auto mt-4 w-full max-w-[320px] overflow-hidden rounded-2xl border border-white/25 bg-white p-3 shadow-[0_16px_45px_rgba(15,23,42,0.42)]">
              <img src={CUSTOMER_QR_IMAGE_PATH} alt="ABA QR" className="w-full h-auto" />
            </div>
            <div className="mt-4 grid grid-cols-2 gap-3 text-sm">
              <div className="rounded-xl border border-white/15 bg-white/10 px-3 py-2.5">
                <p className="text-xs uppercase tracking-[0.12em] text-sky-100/75">Discount</p>
                <p className="mt-1 text-xl font-black text-emerald-200">- {formatCurrency(qrSpotlight.discountAmount)}</p>
              </div>
              <div className="rounded-xl border border-white/20 bg-white/15 px-3 py-2.5">
                <p className="text-xs uppercase tracking-[0.12em] text-sky-100/80">Total</p>
                <p className="mt-1 text-xl font-black text-white">{formatCurrency(qrSpotlight.total)}</p>
              </div>
            </div>
          </div>
        </div>
      )}
      <header className="z-20 px-6 py-4 border-b border-white/10 bg-slate-950/45 backdrop-blur-xl">
        <div className="flex items-center justify-between gap-4 mx-auto max-w-screen-2xl">
          <div>
            <p className="text-[11px] font-bold uppercase tracking-[0.24em] text-emerald-300">Live POS Screen</p>
            <h1 className="mt-1 text-2xl font-black tracking-tight">KH Mart Customer View</h1>
            <p className="text-sm text-emerald-100/85">Scanned products update in realtime</p>
          </div>
          <div className="flex items-center gap-3">
            <div className="flex items-center gap-2">
              <button
                type="button"
                onClick={goBackToStaff}
                className="inline-flex items-center px-3 py-2 text-sm font-bold text-white transition border rounded-xl border-white/15 bg-white/10 hover:bg-white/15"
              >
                Back to Staff
              </button>
              <button
                type="button"
                onClick={toggleFullscreen}
                className="inline-flex items-center gap-2 px-3 py-2 text-sm font-bold text-white transition border rounded-xl border-white/15 bg-white/10 hover:bg-white/15"
              >
                {isFullscreen ? <Minimize2 className="w-4 h-4" /> : <Expand className="w-4 h-4" />}
                {isFullscreen ? 'Exit Fullscreen' : 'Fullscreen'}
              </button>
            </div>
            <div className="text-right">
              <p className="text-xl font-black tabular-nums">{now.toLocaleTimeString('en-US', { hour: '2-digit', minute: '2-digit', second: '2-digit' })}</p>
              <p className="text-sm text-emerald-200/90">{now.toLocaleDateString('en-US', { weekday: 'long', year: 'numeric', month: 'long', day: 'numeric' })}</p>
            </div>
          </div>
        </div>
      </header>

      <main className="h-[calc(100vh-98px)] px-6 py-4 mx-auto max-w-screen-2xl">
        <div className="grid h-full gap-4 lg:grid-cols-[minmax(0,1fr)_340px]">
          <section className="flex h-full flex-col overflow-hidden rounded-2xl border border-white/15 bg-white/[0.08] shadow-[0_12px_36px_rgba(2,6,23,0.35)]">
            <div className="flex items-center justify-between px-4 py-2.5 border-b border-white/10">
              <h2 className="text-lg font-black tracking-tight text-white">Current Order</h2>
              <span className="px-3 py-1 text-xs font-bold border rounded-full border-emerald-300/30 bg-emerald-400/10 text-emerald-100">
                {itemCount} item(s)
              </span>
            </div>

            <div className="grid grid-cols-[minmax(0,1fr)_68px_88px_104px] gap-2 border-b border-white/10 px-4 py-2 text-xs font-bold uppercase tracking-[0.12em] text-emerald-200/80">
              <span>Product</span>
              <span className="text-center">Qty</span>
              <span className="text-right">Price</span>
              <span className="text-right">Total</span>
            </div>

            <div className="flex-1 px-3 py-2 overflow-hidden">
              {cart.length === 0 ? (
                <div className="flex h-full min-h-[220px] items-center justify-center rounded-xl border border-dashed border-white/15 bg-slate-950/20 px-6 text-center">
                  <div>
                    <h3 className="text-2xl font-black text-white">Waiting for scanned products...</h3>
                    <p className="mt-2 text-emerald-100/85">Items scanned in POS will appear here in realtime.</p>
                  </div>
                </div>
              ) : (
                <div className="space-y-2">
                  {cart.map((item, index) => (
                    <div
                      key={`${item.productId || index}-${index}`}
                      className="grid grid-cols-[48px_minmax(0,1fr)_68px_88px_104px] items-center gap-2 rounded-xl border border-white/10 bg-slate-950/20 px-2 py-2"
                    >
                      <div className="overflow-hidden rounded-lg w-11 h-11 bg-black/25">
                        {item.imageUrl ? (
                          <img
                            src={toAbsoluteImageUrl(item.imageUrl)}
                            alt={item.productName || 'Product'}
                            className="object-cover w-full h-full"
                          />
                        ) : (
                          <div className="flex h-full w-full items-center justify-center text-[10px] text-slate-300">No Img</div>
                        )}
                      </div>
                      <div className="min-w-0">
                        <p className="text-sm font-black text-white truncate">{item.productName || 'Unnamed Product'}</p>
                        <p className="text-xs text-emerald-100/80">Realtime POS item</p>
                      </div>
                      <div className="text-sm font-black text-center text-emerald-200">x{Number(item.qty) || 0}</div>
                      <div className="text-sm font-bold text-right text-white">{formatCurrency(item.price)}</div>
                      <div className="text-base font-black text-right text-emerald-200">{formatCurrency(item.lineTotal)}</div>
                    </div>
                  ))}
                </div>
              )}
            </div>
          </section>

          <aside className="flex flex-col h-full gap-3">
            <div className="rounded-2xl border border-white/15 bg-white/[0.08] p-3 shadow-[0_12px_36px_rgba(2,6,23,0.35)]">
              <div className="flex items-center justify-between">
                <p className="text-xs font-bold uppercase tracking-[0.12em] text-emerald-200">Payment Method</p>
                <span className="rounded-full border border-sky-300/30 bg-sky-400/10 px-2.5 py-1 text-xs font-bold text-sky-100">
                  {paymentMethod}
                </span>
              </div>
            </div>

            <div className="flex-1 space-y-3 overflow-hidden">
              <div className="rounded-2xl border border-white/15 bg-white/[0.08] p-3 shadow-[0_12px_36px_rgba(2,6,23,0.35)]">
                <div className="space-y-1.5 text-sm">
                  <div className="flex items-center justify-between text-emerald-100/80">
                    <span>Subtotal</span>
                    <span className="font-bold text-white">{formatCurrency(subtotal)}</span>
                  </div>
                  <div className="flex items-center justify-between text-emerald-100/80">
                    <span>Discount</span>
                    <span className="font-bold text-emerald-200">- {formatCurrency(discountAmount)}</span>
                  </div>
                  <div className="flex items-center justify-between pt-2 border-t border-white/10">
                    <span className="text-base font-black">Grand Total</span>
                    <span className="text-2xl font-black text-emerald-200">{formatCurrency(total)}</span>
                  </div>
                </div>
              </div>

              {total > 0 ? (
                <div className="rounded-2xl border border-sky-200/40 bg-sky-500/10 p-3 text-center shadow-[0_12px_36px_rgba(2,6,23,0.35)]">
                  <p className="text-xs font-bold uppercase tracking-[0.12em] text-sky-200">Scan to Pay</p>
                  <p className="mt-1 text-base font-black text-white">KHQR Payment</p>
                  <div className="mx-auto mt-2.5 w-full max-w-[190px] overflow-hidden rounded-xl border border-white/20 bg-white p-2">
                    <img src={CUSTOMER_QR_IMAGE_PATH} alt="ABA QR" className="w-full h-auto" />
                  </div>
                  <p className="mt-2 text-lg font-black text-emerald-100">{formatCurrency(total)}</p>
                </div>
              ) : null}

              <div className="rounded-2xl border border-white/15 bg-white/[0.08] p-3 shadow-[0_12px_36px_rgba(2,6,23,0.35)]">
                <p className="text-xs font-bold uppercase tracking-[0.12em] text-emerald-200">Cash Summary</p>
                <div className="mt-2 space-y-1.5 text-sm text-emerald-100/85">
                  <div className="flex items-center justify-between">
                    <span>Received</span>
                    <span className="font-bold text-white">{formatCurrency(amountTendered)}</span>
                  </div>
                  <div className="flex items-center justify-between">
                    <span>Change</span>
                    <span className="font-bold text-emerald-200">{formatCurrency(changeAmount)}</span>
                  </div>
                </div>
              </div>

              {displayState.updatedAt && (
                <p className="text-[11px] text-right text-emerald-100/70">
                  Last update: {new Date(displayState.updatedAt).toLocaleTimeString('en-US')}
                </p>
              )}
            </div>
          </aside>
        </div>
      </main>
    </div>
  );
};

export default CustomerDisplay;
